/**
 * Structured events extracted from sessions.
 */

export type EventType =
  | "file_read"
  | "file_write"
  | "search"
  | "tool_call"
  | "test_run"
  | "command_run"
  | "retry"
  | "plan_revision";

export interface SessionEvent {
  type: EventType;
  index: number;
  messageIndex: number;
  timestamp?: string;
  data: EventData;
}

export interface FileReadEvent {
  path: string;
  linesRead?: number;
}

export interface FileWriteEvent {
  path: string;
  linesChanged?: number;
  isCreation: boolean;
}

export interface SearchEvent {
  query: string;
  tool: string;
  resultsCount?: number;
}

export interface TestRunEvent {
  command: string;
  passed: boolean;
  output?: string;
}

export interface CommandRunEvent {
  command: string;
  exitCode?: number;
  output?: string;
}

export interface RetryEvent {
  originalIndex: number;
  reason: string;
  tool: string;
}

export interface PlanRevisionEvent {
  summary: string;
}

export type EventData =
  | FileReadEvent
  | FileWriteEvent
  | SearchEvent
  | TestRunEvent
  | CommandRunEvent
  | RetryEvent
  | PlanRevisionEvent;

