content.content:
1	/**
2	 * Parser for Claude Code session files.
3	 *
4	 * Supports two formats:
5	 * 1. JSON array of messages (single JSON blob)
6	 * 2. NDJSON (one JSON object per line, as Claude Code exports)
7	 *
8	 * Normalizes into our canonical Session format.
9	 */
10	
11	import type { Session, Message, ToolCall, SessionMetadata } from "../types/index.js";
12	
13	export function parseClaudeSession(raw: string): Session {
14	  const entries = parseRawEntries(raw);
15	  const messages = extractMessages(entries);
16	  const toolCalls = extractToolCalls(messages);
17	  const metadata = buildMetadata(messages, toolCalls, entries);
18	
19	  return {
20	    id: extractSessionId(entries) || `session-${Date.now()}`,
21	    provider: "claude",
22	    startTime: findTimestamp(entries, "first"),
23	    endTime: findTimestamp(entries, "last"),
24	    messages,
25	    toolCalls,
26	    metadata,
27	  };
28	}
29	
30	// --- Raw entry parsing ---
31	
32	interface RawEntry {
33	  type?: string;
34	  role?: string;
35	  message?: {
36	    role?: string;
37	    content?: unknown;
38	    model?: string;
39	  };
40	  content?: unknown;
41	  content_block?: {
42	    type?: string;
43	    name?: string;
44	    input?: unknown;
45	    text?: string;
46	  };
47	  model?: string;
48	  timestamp?: string;
49	  // Claude Code NDJSON fields
50	  parentMessageId?: string;
51	  sessionId?: string;
52	  uuid?: string;
53	  cwd?: string;
54	  toolUseResult?: unknown;
55	  isSidechain?: boolean;
56	}
57	
58	function parseRawEntries(raw: string): RawEntry[] {
59	  const trimmed = raw.trim();
60	
61	  // Try JSON array first
62	  if (trimmed.startsWith("[")) {
63	    try {
64	      const parsed = JSON.parse(trimmed);
65	      if (Array.isArray(parsed)) return parsed;
66	    } catch {
67	      // Fall through to NDJSON
68	    }
69	  }
70	
71	  // Try NDJSON
72	  const lines = trimmed.split("\n").filter((l) => l.trim());
73	  const entries: RawEntry[] = [];
74	  for (const line of lines) {
75	    try {
76	      entries.push(JSON.parse(line));
77	    } catch {
78	      // Skip malformed lines
79	    }
80	  }
81	
82	  if (entries.length === 0) {
83	    throw new Error(
84	      "Could not parse session file. Expected JSON array or NDJSON format."
85	    );
86	  }
87	
88	  return entries;
89	}
90	
91	// --- Message extraction ---
92	
93	function extractMessages(entries: RawEntry[]): Message[] {
94	  const messages: Message[] = [];
95	  let index = 0;
96	
97	  for (const entry of entries) {
98	    const role = resolveRole(entry);
99	    if (!role) continue;
100	
101	    const content = resolveContent(entry);
102	    const toolCalls = resolveToolCallsFromEntry(entry, index);
103	
104	    messages.push({
105	      index,
106	      role,
107	      content,
108	      timestamp: entry.timestamp,
109	      toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
110	    });
111	    index++;
112	  }
113	
114	  return messages;
115	}
116	
117	function resolveRole(
118	  entry: RawEntry
119	): "user" | "assistant" | "system" | "tool" | null {
120	  // Direct role field
121	  if (entry.role === "user" || entry.role === "assistant" || entry.role === "system") {
122	    return entry.role;
123	  }
124	
125	  // Nested message.role
126	  if (entry.message?.role) {
127	    const r = entry.message.role;
128	    if (r === "user" || r === "assistant" || r === "system") return r;
129	  }
130	
131	  // Tool results
132	  if (entry.type === "tool_result" || entry.toolUseResult !== undefined) {
133	    return "tool";
134	  }
135	
136	  // Content blocks from assistant
137	  if (entry.type === "content_block_delta" || entry.type === "content_block_start") {
138	    return "assistant";
139	  }
140	
141	  return null;
142	}
143	
144	function resolveContent(entry: RawEntry): string {
145	  // Direct string content
146	  if (typeof entry.content === "string") return entry.content;
147	
148	  // Array of content blocks (Claude API format)
149	  if (Array.isArray(entry.content)) {
150	    return entry.content
151	      .map((block: { type?: string; text?: string }) => {
152	        if (typeof block === "string") return block;
153	        if (block.type === "text" && block.text) return block.text;
154	        if (block.type === "tool_use") return `[Tool: ${(block as Record<string, unknown>).name}]`;
155	        if (block.type === "tool_result") {
156	          const result = block as Record<string, unknown>;
157	          if (typeof result.content === "string") return result.content;
158	          return "[Tool Result]";
159	        }
160	        return "";
161	      })
162	      .filter(Boolean)
163	      .join("\n");
164	  }
165	
166	  // Nested message.content
167	  if (entry.message?.content) {
168	    if (typeof entry.message.content === "string") return entry.message.content;
169	    if (Array.isArray(entry.message.content)) {
170	      return (entry.message.content as Array<{ type?: string; text?: string }>)
171	        .map((block) => {
172	          if (typeof block === "string") return block;
173	          if (block.text) return block.text;
174	          return "";
175	        })
